import { createClient } from 'jsr:@supabase/supabase-js@2';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

/**
 * Returns the UTC offset string for US Central Time based on the current date.
 * Uses the Intl API to detect whether CDT (-05:00) or CST (-06:00) is in effect.
 */
function getCentralTimeOffset(): string {
  const now = new Date();
  const formatter = new Intl.DateTimeFormat('en-US', {
    timeZone: 'America/Chicago',
    timeZoneName: 'short',
  });
  const parts = formatter.formatToParts(now);
  const tzName = parts.find(p => p.type === 'timeZoneName')?.value;
  return tzName === 'CDT' ? '-05:00' : '-06:00';
}

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders });
  }

  try {
    const supabaseClient = createClient(
      Deno.env.get('SUPABASE_URL') ?? '',
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
    );

    // Helper to insert a notification_log row without throwing
    async function log(row: Record<string, unknown>) {
      const { error } = await supabaseClient.from('notification_log').insert([row]);
      if (error) console.error('notification_log insert error:', error);
    }

    console.log('Starting service reminder check...');

    // Get all churches with notification settings enabled
    const { data: notificationSettings, error: settingsError } = await supabaseClient
      .from('notification_settings')
      .select('church_id, notification_hours')
      .eq('enabled', true);

    if (settingsError) {
      console.error('Error fetching notification settings:', settingsError);
      return new Response(
        JSON.stringify({ error: 'Error fetching notification settings' }),
        { status: 500, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      );
    }

    console.log('Found', notificationSettings?.length || 0, 'churches with notifications enabled');

    let totalNotificationsSent = 0;

    // Determine Central Time offset once for this invocation
    const centralTimeOffset = getCentralTimeOffset();
    console.log('Using Central Time offset:', centralTimeOffset);

    // Process each church
    for (const settings of notificationSettings || []) {
      const churchId = settings.church_id;
      const notificationHours = settings.notification_hours || [24];

      console.log('Processing church:', churchId, 'with notification hours:', notificationHours);

      for (const hours of notificationHours) {
        const now = new Date();
        const targetServiceTime = new Date(now.getTime() + hours * 60 * 60 * 1000);
        const windowStart = new Date(targetServiceTime.getTime() - 30 * 60 * 1000);
        const windowEnd = new Date(targetServiceTime.getTime() + 30 * 60 * 1000);

        console.log('Current time:', now.toISOString());
        console.log('Looking for services between', windowStart.toISOString(), 'and', windowEnd.toISOString());
        console.log('(Services that are approximately', hours, 'hours from now)');

        // Get services in the date range
        const { data: services, error: servicesError } = await supabaseClient
          .from('services')
          .select('id, service_type, date, time')
          .eq('church_id', churchId)
          .gte('date', windowStart.toISOString().split('T')[0])
          .lte('date', windowEnd.toISOString().split('T')[0]);

        if (servicesError) {
          console.error('Error fetching services:', servicesError);
          continue;
        }

        console.log('Found', services?.length || 0, 'services in date range');

        if (!services || services.length === 0) {
          console.log('No services found in date range for church', churchId);
          await log({
            church_id: churchId,
            hours_setting: hours,
            window_start: windowStart.toISOString(),
            window_end: windowEnd.toISOString(),
            notes: 'no services found in date range',
          });
          continue;
        }

        // Filter services by combining date + time and checking if they fall in the window
        const matchingServices: typeof services = [];

        for (const service of services) {
          // Guard against null time
          if (!service.time) {
            console.log('Skipping service with null time:', service.id);
            await log({
              church_id: churchId,
              service_id: service.id,
              service_type: service.service_type,
              service_date: service.date,
              service_time: null,
              hours_setting: hours,
              window_start: windowStart.toISOString(),
              window_end: windowEnd.toISOString(),
              notes: 'skipped: null time',
            });
            continue;
          }

          const timeParts = service.time.split(':');
          const timeStr = timeParts.length === 2 ? `${service.time}:00` : service.time;
          const serviceDateTime = new Date(`${service.date}T${timeStr}${centralTimeOffset}`);

          // Log every service found in the date range before window check
          console.log('Checking service in date range:', service.id, serviceDateTime.toISOString());
          await log({
            church_id: churchId,
            service_id: service.id,
            service_type: service.service_type,
            service_date: service.date,
            service_time: service.time,
            service_datetime_parsed: serviceDateTime.toISOString(),
            hours_setting: hours,
            window_start: windowStart.toISOString(),
            window_end: windowEnd.toISOString(),
            notes: 'found in date range, checking window',
          });

          const isInWindow = serviceDateTime >= windowStart && serviceDateTime <= windowEnd;

          if (isInWindow) {
            const hoursUntilService = (serviceDateTime.getTime() - now.getTime()) / (1000 * 60 * 60);
            console.log('✅ Service matches window:', {
              service: service.service_type,
              serviceDateTime: serviceDateTime.toISOString(),
              windowStart: windowStart.toISOString(),
              windowEnd: windowEnd.toISOString(),
              hoursUntilService: hoursUntilService.toFixed(2),
              targetHours: hours,
              centralTimeOffset,
            });
            matchingServices.push(service);
          } else {
            console.log('Service outside window, skipping:', service.id);
            await log({
              church_id: churchId,
              service_id: service.id,
              service_type: service.service_type,
              service_date: service.date,
              service_time: service.time,
              service_datetime_parsed: serviceDateTime.toISOString(),
              hours_setting: hours,
              window_start: windowStart.toISOString(),
              window_end: windowEnd.toISOString(),
              notes: 'skipped: outside time window',
