import { createClient } from 'jsr:@supabase/supabase-js@2';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

/**
 * Returns the UTC offset string for US Central Time based on the current date.
 * Uses the Intl API to detect whether CDT (-05:00) or CST (-06:00) is in effect.
 */
function getCentralTimeOffset(): string {
  const now = new Date();
  const formatter = new Intl.DateTimeFormat('en-US', {
    timeZone: 'America/Chicago',
    timeZoneName: 'short',
  });
  const parts = formatter.formatToParts(now);
  const tzName = parts.find(p => p.type === 'timeZoneName')?.value;
  return tzName === 'CDT' ? '-05:00' : '-06:00';
}

