    let totalNotificationsSent = 0;

    // Determine Central Time offset once for this invocation
    const centralTimeOffset = getCentralTimeOffset();
    console.log('Using Central Time offset:', centralTimeOffset);

    // Process each church
    for (const settings of notificationSettings || []) {
      const churchId = settings.church_id;
      const notificationHours = settings.notification_hours || [24];

      console.log('Processing church:', churchId, 'with notification hours:', notificationHours);

      for (const hours of notificationHours) {
