            console.log('Service outside window, skipping:', service.id);
            await log({
              church_id: churchId,
              service_id: service.id,
              service_type: service.service_type,
              service_date: service.date,
              service_time: service.time,
              service_datetime_parsed: serviceDateTime.toISOString(),
              hours_setting: hours,
              window_start: windowStart.toISOString(),
              window_end: windowEnd.toISOString(),
              notes: 'skipped: outside time window',
            });
          }
        }

