        const { data: services, error: servicesError } = await supabaseClient
          .from('services')
          .select('id, service_type, date, time')
          .eq('church_id', churchId)
          .gte('date', dateFrom)
          .lte('date', dateTo);

        if (servicesError) {
          console.error('Error fetching services:', servicesError);
          await log({
            church_id: churchId,
            hours_setting: hours,
            window_start: windowStart.toISOString(),
            window_end: windowEnd.toISOString(),
            notes: 'error fetching services: ' + JSON.stringify(servicesError),
          });
          continue;
        }

        console.log('Found', services?.length || 0, 'services in date range');

        if (!services || services.length === 0) {
          await log({
            church_id: churchId,
            hours_setting: hours,
            window_start: windowStart.toISOString(),
            window_end: windowEnd.toISOString(),
            notes: 'no services found in date range',
          });
          continue;
        }

        const matchingServices: typeof services = [];

        for (const service of services) {
          if (!service.time) {
            await log({
              church_id: churchId,
              service_id: service.id,
              service_type: service.service_type,
              service_date: service.date,
              hours_setting: hours,
              window_start: windowStart.toISOString(),
              window_end: windowEnd.toISOString(),
              notes: 'skipped: null time',
            });
            continue;
          }

          const timeParts = service.time.split(':');
          const timeStr = timeParts.length === 2 ? `${service.time}:00` : service.time;
          const serviceDateTime = new Date(`${service.date}T${timeStr}${centralTimeOffset}`);

          const isInWindow = serviceDateTime >= windowStart && serviceDateTime <= windowEnd;

          await log({
            church_id: churchId,
            service_id: service.id,
            service_type: service.service_type,
            service_date: service.date,
            service_time: service.time,
            service_datetime_parsed: serviceDateTime.toISOString(),
            hours_setting: hours,
            window_start: windowStart.toISOString(),
            window_end: windowEnd.toISOString(),
            notes: isInWindow ? 'matched window' : 'outside window',
          });

          if (isInWindow) {
            console.log('Matched:', service.service_type, serviceDateTime.toISOString());
            matchingServices.push(service);
          }
        }

        for (const service of matchingServices) {
          const timeParts = service.time.split(':');
          const timeStr = timeParts.length === 2 ? `${service.time}:00` : service.time;
          const serviceDateTime = new Date(`${service.date}T${timeStr}${centralTimeOffset}`);

          const { data: assignments, error: assignmentsError } = await supabaseClient
            .from('assignments')
            .select('member_id, role, person_name')
            .eq('service_id', service.id)
            .not('member_id', 'is', null);

          if (assignmentsError) {
            console.error('Error fetching assignments:', assignmentsError);
            continue;
          }

          const churchMemberIds = [...new Set((assignments || []).map(a => a.member_id).filter(Boolean))];

          if (churchMemberIds.length === 0) {
            await log({
              church_id: churchId,
              service_id: service.id,
              service_type: service.service_type,
              service_date: service.date,
              service_time: service.time,
              service_datetime_parsed: serviceDateTime.toISOString(),
              hours_setting: hours,
              members_found: 0,
              tokens_found: 0,
              notifications_sent: 0,
              notes: 'skipped: no members assigned',
            });
            continue;
          }

          const { data: pushTokens, error: tokensError } = await supabaseClient
            .from('push_tokens')
            .select('token, member_id')
            .in('member_id', churchMemberIds);

          if (tokensError) {
            console.error('Error fetching push tokens:', tokensError);
            continue;
          }

          if (!pushTokens || pushTokens.length === 0) {
            await log({
              church_id: churchId,
              service_id: service.id,
              service_type: service.service_type,
              service_date: service.date,
              service_time: service.time,
              service_datetime_parsed: serviceDateTime.toISOString(),
              hours_setting: hours,
              members_found: churchMemberIds.length,
              tokens_found: 0,
              notifications_sent: 0,
              notes: 'skipped: no push tokens found',
            });
            continue;
          }

          const tokenMap = new Map<string, string[]>();
          for (const pt of pushTokens) {
            if (!tokenMap.has(pt.member_id)) tokenMap.set(pt.member_id, []);
            tokenMap.get(pt.member_id)?.push(pt.token);
          }

          const serviceDate = new Date(service.date + 'T12:00:00Z').toLocaleDateString('en-US', {
            weekday: 'long',
            month: 'short',
            day: 'numeric',
            year: 'numeric',
          });
          const timeText = service.time || '';
          const hoursText = hours === 1 ? '1 hour' : `${hours} hours`;

          const messages: any[] = [];

          for (const assignment of assignments || []) {
            if (!assignment.member_id) continue;
            const tokens = tokenMap.get(assignment.member_id) || [];
            for (const token of tokens) {
              messages.push({
                to: token,
                sound: 'default',
                title: `Service Reminder: ${service.service_type}`,
                body: `You're scheduled for ${assignment.role} on ${serviceDate}${timeText ? ` at ${timeText}` : ''} (in ${hoursText})`,
                data: {
                  serviceId: service.id,
                  type: 'service_reminder',
                  role: assignment.role,
                  date: service.date,
                },
              });
            }
          }

          if (messages.length > 0) {
            console.log('Sending', messages.length, 'notifications for service', service.id);
            const response = await fetch('https://exp.host/--/api/v2/push/send', {
              method: 'POST',
              headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json',
              },
              body: JSON.stringify(messages),
            });

            const expoResponseText = await response.text();
            console.log('Expo response:', expoResponseText);

            if (!response.ok) {
              await log({
                church_id: churchId,
                service_id: service.id,
                service_type: service.service_type,
                service_date: service.date,
                service_time: service.time,
                service_datetime_parsed: serviceDateTime.toISOString(),
                hours_setting: hours,
                members_found: churchMemberIds.length,
                tokens_found: pushTokens.length,
                notifications_sent: 0,
                expo_response: expoResponseText,
                notes: 'expo push HTTP error',
              });
            } else {
              let parsedResponse: any = {};
              try { parsedResponse = JSON.parse(expoResponseText); } catch (_) {}
              if (parsedResponse.data) {
                for (const item of parsedResponse.data) {
                  if (item.status === 'error') {
                    console.error('Per-message push error:', JSON.stringify(item));
                  }
                }
              }
              totalNotificationsSent += messages.length;
              await log({
                church_id: churchId,
                service_id: service.id,
                service_type: service.service_type,
                service_date: service.date,
                service_time: service.time,
                service_datetime_parsed: serviceDateTime.toISOString(),
                hours_setting: hours,
                members_found: churchMemberIds.length,
                tokens_found: pushTokens.length,
                notifications_sent: messages.length,
                expo_response: expoResponseText,
                notes: 'notifications sent successfully',
              });
            }
          } else {
            await log({
              church_id: churchId,
              service_id: service.id,
              service_type: service.service_type,
              service_date: service.date,
              service_time: service.time,
              service_datetime_parsed: serviceDateTime.toISOString(),
              hours_setting: hours,
              members_found: churchMemberIds.length,
              tokens_found: pushTokens.length,
              notifications_sent: 0,
              notes: 'skipped: no messages built',
            });
          }
        }
      }
    }

    console.log('Done. Total notifications sent:', totalNotificationsSent);

    return new Response(
      JSON.stringify({ success: true, notificationsSent: totalNotificationsSent }),
      { status: 200, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
    );
  } catch (error) {
    console.error('Error in send-service-reminders:', error);
    return new Response(
      JSON.stringify({ error: error.message }),
      { status: 500, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
    );
  }
});

